52	    modifier: Modifier = Modifier,
53	    fontScale: Float = 1f,
54	    onMentionClick: ((handle: String) -> Unit)? = null,
55	    onLinkClick: ((url: String) -> Unit)? = null,
56	    onTextClick: (() -> Unit)? = null
57	) {
58	    val uriHandler = LocalUriHandler.current
59	    val colors = LocalAppColors.current
60	    val linkColor = colors.accent
61	    val mentionBg = colors.accent.copy(alpha = 0.10f)
62	    val codeBg = colors.surface
63	    val textColor = colors.textBody
64	
65	    val effectiveFontScale = if (fontScale != 1f) fontScale else LocalFontScale.current
66	    val baseStyle = LocalAppTypography.current.bodyLarge.copy(color = textColor)
67	    val bodyStyle = if (effectiveFontScale != 1f) {
68	        baseStyle.copy(fontSize = baseStyle.fontSize * effectiveFontScale)
69	    } else baseStyle
70	
71	    if (maxLines < Int.MAX_VALUE) {
72	        // Preview mode: flat AnnotatedString (no block code highlighting)
