async function getEmailMessage({ locale, to, verifyUrlTemplate, token }: {
  locale: Intl.Locale;
  to: string;
  verifyUrlTemplate: string;
  token: SigninToken;
}): Promise<Message> {
  const verifyUrl = parseTemplate(verifyUrlTemplate).expand({
    token: token.token,
    code: token.code,
  });
  const expiration = EXPIRATION.toLocaleString(locale.baseName, {
    // @ts-ignore: DurationFormatOptions, not DateTimeFormatOptions
    style: "long",
  });
  const template = await getEmailTemplate(locale);
  const textContent = template.content
    .replaceAll(/\{\{(verifyUrl|code|expiration)\}\}/g, (m) => {
      return m === "{{verifyUrl}}"
        ? verifyUrl
        : m === "{{code}}"
        ? token.code
        : expiration;
    });
  return createMessage({
    from: EMAIL_FROM,
    to,
    subject: template.subject,
    content: {
      text: textContent,
      html: (() => {
        const parsed = URL.canParse(verifyUrl) ? new URL(verifyUrl) : null;
        if (
          parsed == null ||
          !["https:", "http:", "hackerspub:"].includes(parsed.protocol)
        ) {
          throw new Error(`Unsupported verify URL scheme: ${verifyUrl}`);
        }
        const safeVerifyUrl = parsed.toString();
        const escapedText = escape(textContent);
        const escapedUrl = escape(safeVerifyUrl);
        return escapedText
          .replaceAll(
            escapedUrl,
            `<a href="${escapedUrl}">${escapedUrl}</a>`,
          )
          .replaceAll("\n", "<br>\n");
      })(),
    },
  });
}

