@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun ExploreScreen(
    onPostClick: (String) -> Unit,
    onProfileClick: (String) -> Unit,
    onReplyClick: (String) -> Unit,
    onQuoteClick: (String) -> Unit = {},
    onSignInClick: () -> Unit,
    isLoggedIn: Boolean,
    viewModel: ExploreViewModel = hiltViewModel()
) {
    val uiState by viewModel.uiState.collectAsState()
    val listState = rememberLazyListState()
    val context = LocalContext.current
    val colors = LocalAppColors.current
    val typography = LocalAppTypography.current

    val shouldLoadMore by remember {
        derivedStateOf {
            val lastVisibleItem = listState.layoutInfo.visibleItemsInfo.lastOrNull()
            lastVisibleItem != null && lastVisibleItem.index >= listState.layoutInfo.totalItemsCount - 3
        }
    }

    LaunchedEffect(shouldLoadMore) {
        if (shouldLoadMore && uiState.hasNextPage && !uiState.isLoadingMore) {
            viewModel.loadMore()
        }
    }

    LaunchedEffect(uiState.selectedTab) {
        listState.scrollToItem(0)
    }

    Scaffold(
        contentWindowInsets = WindowInsets(0),
        topBar = {
            LargeTitleHeader(
                title = "Explore",
                trailingContent = if (!isLoggedIn) {
                    {
                        TextButton(onClick = onSignInClick) {
                            Text(stringResource(R.string.sign_in))
                        }
                    }
                } else null
            )
        }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
        ) {
            // Custom tab row
            Row(modifier = Modifier.fillMaxWidth()) {
                ExploreTab.entries.forEach { tab ->
                    val isSelected = uiState.selectedTab == tab
                    Column(
                        modifier = Modifier
                            .weight(1f)
                            .clickable { viewModel.selectTab(tab) },
                        horizontalAlignment = Alignment.CenterHorizontally
                    ) {
                        Text(
                            text = when (tab) {
                                ExploreTab.LOCAL -> "Local"
                                ExploreTab.GLOBAL -> "Global"
                            },
                            style = if (isSelected) typography.bodyLargeSemiBold else typography.bodyLarge,
                            color = if (isSelected) colors.accent else colors.textSecondary,
                            modifier = Modifier.padding(vertical = 12.dp)
                        )
                        if (isSelected) {
                            Box(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(2.dp)
                                    .background(colors.accent)
                            )
                        } else {
                            Box(
                                modifier = Modifier
                                    .fillMaxWidth()
                                    .height(2.dp)
                            )
                        }
                    }
                }
            }

            HorizontalDivider(
                color = colors.divider,
                thickness = 1.dp,
                modifier = Modifier.padding(horizontal = 16.dp)
            )

            Box(modifier = Modifier.fillMaxSize()) {
                when {
                    uiState.isLoading && uiState.posts.isEmpty() -> {
                        FullScreenLoading()
                    }
                    uiState.error != null && uiState.posts.isEmpty() -> {
                        ErrorMessage(
                            message = uiState.error ?: stringResource(R.string.error_generic),
                            onRetry = { viewModel.refresh() }
                        )
                    }
                    uiState.posts.isEmpty() -> {
                        ErrorMessage(
                            message = stringResource(R.string.no_posts)
                        )
                    }
                    else -> {
                        PullToRefreshBox(
                            isRefreshing = uiState.isRefreshing,
                            onRefresh = { viewModel.refresh() }
                        ) {
                            LazyColumn(
                                state = listState
                            ) {
                                items(
                                    items = uiState.posts,
                                    key = { it.id }
                                ) { post ->
                                    PostCard(
                                        post = post,
                                        onClick = { onPostClick(post.sharedPost?.id ?: post.id) },
                                        onProfileClick = onProfileClick,
                                        onReplyClick = if (isLoggedIn) {
                                            { onReplyClick(post.sharedPost?.id ?: post.id) }
                                        } else null,
                                        onShareClick = if (isLoggedIn) {
                                            {
                                                if (post.viewerHasShared) {
                                                    viewModel.unsharePost(post.id)
                                                } else {
                                                    viewModel.sharePost(post.id)
                                                }
                                            }
                                        } else null,
                                        onQuoteClick = if (isLoggedIn) {
                                            { onQuoteClick(post.sharedPost?.id ?: post.id) }
                                        } else null,
                                        onReactionClick = { onPostClick(post.sharedPost?.id ?: post.id) },
                                        onExternalShareClick = {
                                            val displayPost = post.sharedPost ?: post
                                            val shareUrl = displayPost.url ?: displayPost.iri
                                            if (shareUrl != null) {
                                                val sendIntent = Intent().apply {
                                                    action = Intent.ACTION_SEND
                                                    putExtra(Intent.EXTRA_TEXT, shareUrl)
                                                    type = "text/plain"
                                                }
                                                context.startActivity(Intent.createChooser(sendIntent, null))
                                            }
                                        },
                                        onQuotedPostClick = onPostClick
                                    )
                                    HorizontalDivider(
                                        color = colors.divider,
                                        thickness = 1.dp,
                                        modifier = Modifier.padding(horizontal = 16.dp)
                                    )
                                }

                                if (uiState.isLoadingMore) {
                                    item {
                                        LoadingItem()
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }
}

