            "ul" -> {
                if (hasContent && listStack.isEmpty()) append("\n")
                listStack.add(ListContext(ordered = false))
            }
            "ol" -> {
                if (hasContent && listStack.isEmpty()) append("\n")
                listStack.add(ListContext(ordered = true))
            }
