                val ctx = listStack.lastOrNull()
                val indent = "  ".repeat((listStack.size - 1).coerceAtLeast(0))
                if (ctx != null) {
                    if (ctx.ordered) {
                        ctx.itemIndex++
                        append("${indent}${ctx.itemIndex}. ")
                    } else {
                        append("${indent}\u2022 ")
                    }
                }
                insideListItem = true
                hasContent = true
            }

